#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=105;
int n,m,vis[N],c[N];
struct node
{
	int v,w;
};
vector<node> g[N];
queue<int> q;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1;i<=n;i++) 
	{
		int x;
		cin>>c[i]>>x;
		if(c[i]>0)
		{
			q.push(i);
			vis[i]=1;
		}
		else
		{
			c[i]-=x;
		}
//		cout<<c[i]<<" ";
	}
//	cout<<"\n";
	for(int i=1;i<=m;i++)
	{
		int u,v,w;
		cin>>u>>v>>w;
		g[u].push_back(node{v,w});
	}
	while(!q.empty())
	{
		int u=q.front();
//		cout<<u<<" ";
		q.pop();
		if(c[u]<=0) continue; 
		for(int i=0;i<g[u].size();i++)
		{
			int v=g[u][i].v,w=g[u][i].w;
			c[v]+=(w*c[u]);
			if(!vis[v])
			{
				q.push(v);
				vis[v]=1;
			}
		}
	}
//	cout<<"\n";
	bool flag=1;
//	for(int i=1;i<=n;i++) 
//	{
//		cout<<c[i]<<" ";
//	}
//	cout<<"\n";
	for(int i=1;i<=n;i++)
	{
		if(g[i].size()||(c[i]<=0)) continue;
		flag=0;
		cout<<i<<" "<<c[i]<<"\n";
	}
	if(flag) cout<<"NULL";
	return 0;
}
